import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Modifying;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.math.BigDecimal;
import java.util.List;
import java.util.Optional;

@Repository
public interface UserRepository extends JpaRepository<User, Long> {

    Optional<User> findByUsername(String username);

    Optional<User> findByEmail(String email);

    boolean existsByUsername(String username);

    boolean existsByEmail(String email);

    List<User> findByStatus(UserStatus status);

    @Query("SELECT u FROM User u WHERE u.accountBalance > :balance")
    List<User> findUsersWithBalanceGreaterThan(@Param("balance") BigDecimal balance);

    @Query("SELECT u FROM User u LEFT JOIN FETCH u.transactions WHERE u.id = :id")
    Optional<User> findByIdWithTransactions(@Param("id") Long id);

    @Modifying
    @Query("UPDATE User u SET u.status = :status WHERE u.id = :id")
    int updateUserStatus(@Param("id") Long id, @Param("status") UserStatus status);

    @Modifying
    @Query("UPDATE User u SET u.accountBalance = u.accountBalance + :amount WHERE u.id = :id")
    int updateAccountBalance(@Param("id") Long id, @Param("amount") BigDecimal amount);

    List<User> findByFirstNameContainingIgnoreCaseOrLastNameContainingIgnoreCase(
        String firstName, String lastName);
}

