package com.enterprise.service;

import com.enterprise.dto.CreateTransactionRequest;
import com.enterprise.dto.TransactionDTO;
import com.enterprise.entity.Transaction;
import com.enterprise.entity.TransactionStatus;
import com.enterprise.entity.TransactionType;
import com.enterprise.entity.User;
import com.enterprise.repository.TransactionRepository;
import com.enterprise.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.UUID;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Transactional
public class TransactionService {

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionDTO createTransaction(CreateTransactionRequest request) {
        User user = userRepository.findById(request.getUserId())
            .orElseThrow(() -> new RuntimeException("User not found"));

        String referenceNumber = generateReferenceNumber();

        Transaction transaction = Transaction.builder()
            .user(user)
            .amount(request.getAmount())
            .transactionType(request.getTransactionType())
            .description(request.getDescription())
            .referenceNumber(referenceNumber)
            .build();

        Transaction savedTransaction = transactionRepository.save(transaction);
        return convertToDTO(savedTransaction);
    }

    public TransactionDTO processTransaction(Long transactionId) {
        Transaction transaction = transactionRepository.findById(transactionId)
            .orElseThrow(() -> new RuntimeException("Transaction not found"));

        if (transaction.getStatus() != TransactionStatus.PENDING) {
            throw new RuntimeException("Transaction already processed");
        }

        User user = transaction.getUser();
        BigDecimal amount = transaction.getAmount();

        switch (transaction.getTransactionType()) {
            case DEPOSIT:
                user.setAccountBalance(user.getAccountBalance().add(amount));
                break;
            case WITHDRAWAL:
                if (user.getAccountBalance().compareTo(amount) < 0) {
                    transaction.setStatus(TransactionStatus.FAILED);
                    transactionRepository.save(transaction);
                    throw new RuntimeException("Insufficient balance");
                }
                user.setAccountBalance(user.getAccountBalance().subtract(amount));
                break;
            case PAYMENT:
                if (user.getAccountBalance().compareTo(amount) < 0) {
                    transaction.setStatus(TransactionStatus.FAILED);
                    transactionRepository.save(transaction);
                    throw new RuntimeException("Insufficient balance");
                }
                user.setAccountBalance(user.getAccountBalance().subtract(amount));
                break;
            case REFUND:
                user.setAccountBalance(user.getAccountBalance().add(amount));
                break;
        }

        transaction.setStatus(TransactionStatus.COMPLETED);
        userRepository.save(user);
        Transaction updatedTransaction = transactionRepository.save(transaction);

        return convertToDTO(updatedTransaction);
    }

    @Transactional(readOnly = true)
    public TransactionDTO getTransactionById(Long id) {
        Transaction transaction = transactionRepository.findById(id)
            .orElseThrow(() -> new RuntimeException("Transaction not found"));
        return convertToDTO(transaction);
    }

    @Transactional(readOnly = true)
    public List<TransactionDTO> getUserTransactions(Long userId) {
        return transactionRepository.findByUserIdOrderByTransactionDateDesc(userId).stream()
            .map(this::convertToDTO)
            .collect(Collectors.toList());
    }

    @Transactional(readOnly = true)
    public List<TransactionDTO> getTransactionsByStatus(TransactionStatus status) {
        return transactionRepository.findByStatus(status).stream()
            .map(this::convertToDTO)
            .collect(Collectors.toList());
    }

    @Transactional(readOnly = true)
    public List<TransactionDTO> getUserTransactionsBetweenDates(
            Long userId, LocalDateTime startDate, LocalDateTime endDate) {
        return transactionRepository.findUserTransactionsBetweenDates(userId, startDate, endDate)
            .stream()
            .map(this::convertToDTO)
            .collect(Collectors.toList());
    }

    @Transactional(readOnly = true)
    public BigDecimal calculateUserTotalByStatus(Long userId, TransactionStatus status) {
        BigDecimal total = transactionRepository.calculateTotalAmountByUserAndStatus(userId, status);
        return total != null ? total : BigDecimal.ZERO;
    }

    public void cancelTransaction(Long transactionId) {
        Transaction transaction = transactionRepository.findById(transactionId)
            .orElseThrow(() -> new RuntimeException("Transaction not found"));

        if (transaction.getStatus() == TransactionStatus.COMPLETED) {
            throw new RuntimeException("Cannot cancel completed transaction");
        }

        transaction.setStatus(TransactionStatus.CANCELLED);
        transactionRepository.save(transaction);
    }

    private String generateReferenceNumber() {
        return "TXN-" + UUID.randomUUID().toString();
    }

    private TransactionDTO convertToDTO(Transaction transaction) {
        return TransactionDTO.builder()
            .id(transaction.getId())
            .userId(transaction.getUser().getId())
            .amount(transaction.getAmount())
            .transactionType(transaction.getTransactionType())
            .status(transaction.getStatus())
            .description(transaction.getDescription())
            .referenceNumber(transaction.getReferenceNumber())
            .transactionDate(transaction.getTransactionDate())
            .createdAt(transaction.getCreatedAt())
            .build();
    }
}

